query:
SELECT id, entity, status, row_count, TIMESTAMPDIFF(MINUTE, started_at, NOW()) as elapsed_min FROM sync_logs WHERE section='ff365' ORDER BY id DESC LIMIT 8;
SELECT section, COUNT(*) as cnt, SUM(CASE WHEN payment_time IS NOT NULL THEN 1 ELSE 0 END) as has_pt, SUM(CASE WHEN created_by IS NOT NULL THEN 1 ELSE 0 END) as has_cb FROM payment_transactions GROUP BY section;
SELECT COUNT(*) as inst_ff365 FROM installments WHERE section='ff365';

